sp_page.css:
$background-desktop: "223a20eeffa1a2105703ffffffffffa1.iix";
$background-mobile: "e93aac2effa1a2105703ffffffffff90.iix";

main.body {
  background-image: url($background-desktop);
  padding-top: 0rem !important;
  background-repeat: no-repeat;
  background-size: 100% 50rem;
}

/* Padding for container after banner image */
.padding-top {
  padding-top: 2.4rem;
}

/* Padding bottom after each widget */
.child-b-margin > span > div > *{
  margin-bottom: 2.4rem;
}

.mobile-banner {
  background-position: right bottom !important;
}

/* Max width for Containers to stay in view port*/
.container {
  max-width: 100%;
}

.panel-heading
{
  
background: #A8DCD4 !important;
}

@container (max-width: 48em) {
 .page-0987d9aa53331210b8f2ddeeff7b129d main.body {
   background-image: url($background-mobile);
}

  .child-b-margin > span > div > *{
    margin-bottom: 1.6rem;
  }
  .padding-right {
    padding-right: 0rem;
  }
   .padding-top {
    padding-top: 1.6rem;
  }
}

@container (max-width : 62em) {
  .container {
    width : 100%;
  }
  .col-md-4 {
    width : 100%
  }
  .col-md-8 {
    width : 100%
  }
  .left-column{
    padding-left: 2.4rem;
    padding-right: 2.4rem;	
  }	
  .right-column{
    padding-left: 2.4rem;
    padding-right: 2.4rem;	
  }
}

@container (min-width: 62em) {	
  .container {	
    padding-left: 1.2rem;	
    padding-right: 1.2rem;	
  }	
  .left-column{
    padding-right: 0rem;	
  }	
  .right-column{
    padding-left: 2.4rem;
    padding-right: 1.6rem;
  }	
}
